public void PurchaseTickets(int eventId, int purchaseQuantity)
{
    using (var context = new EventBookingContext())
    {
        var event = context.Events.Include(e => e.Tickets).FirstOrDefault(e => e.Id == eventId);
        if (event == null)
        {
            Console.WriteLine("Event not found");
            return;
        }

        if (event.AvailableSeats < purchaseQuantity)
        {
            Console.WriteLine("Not enough seats available");
            return;
        }

        using (var transaction = context.Database.BeginTransaction())
        {
            event.AvailableSeats -= purchaseQuantity;
            context.SaveChanges();
            
            var tickets = new List<Ticket>();
            for (int i = 0; i < purchaseQuantity; i++)
            {
                tickets.Add(new Ticket { EventId = eventId });
            }

            context.Tickets.AddRange(tickets);
            context.SaveChanges();

            transaction.Commit();
        }
    }
}